class Solution:
    def minOperations(self, nums):
        def is_pal(x):
            s = bin(x)[2:]
            return s == s[::-1]

        def nearest(v):
            d = 0
            while True:
                if v - d >= 0 and is_pal(v - d):
                    return d
                if is_pal(v + d):
                    return d
                d += 1

        return [nearest(x) for x in nums]

