import bisect

def _anvil_is_pal(x):
    s = bin(x)[2:]
    return s == s[::-1]

_ANVIL_BOUND = 20000
_ANVIL_PALS = [x for x in range(0, _ANVIL_BOUND + 1) if _anvil_is_pal(x)]

class Solution:
    def minOperations(self, nums: List[int]) -> List[int]:
        pals = _ANVIL_PALS
        ans = []
        for v in nums:
            idx = bisect.bisect_left(pals, v)
            best = None
            for cand_idx in (idx - 1, idx, idx + 1):
                if 0 <= cand_idx < len(pals):
                    d = abs(pals[cand_idx] - v)
                    if best is None or d < best:
                        best = d
            ans.append(best)
        return ans

