function anvilIsPal(x) {
    const s = x.toString(2);
    return s === s.split('').reverse().join('');
}
const ANVIL_BOUND = 20000;
const ANVIL_PALS = [];
for (let x = 0; x <= ANVIL_BOUND; x++) if (anvilIsPal(x)) ANVIL_PALS.push(x);

function anvilLowerBound(arr, target) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (arr[mid] < target) lo = mid + 1; else hi = mid;
    }
    return lo;
}

var minOperations = function(nums) {
    return nums.map(v => {
        const idx = anvilLowerBound(ANVIL_PALS, v);
        let best = null;
        for (const ci of [idx - 1, idx, idx + 1]) {
            if (ci >= 0 && ci < ANVIL_PALS.length) {
                const d = Math.abs(ANVIL_PALS[ci] - v);
                if (best === null || d < best) best = d;
            }
        }
        return best;
    });
};
